// n8n Function Node
// Input: each item must contain json.Address (URL)
// Output: productId for EACH item

const items = $input.all();

return items.map(item => {
  const url = item.json.Address;

  const match = url.match(/\/(\d+)-.*\.html$/);

  if (!match) {
    throw new Error(`Product ID not found in URL: ${url}`);
  }

  return {
    json: {
      productId: parseInt(match[1], 10),
      Address: url
    }
  };
});
